-- BM.14.01: BẢNG KIỂM GIÁM SÁT TUÂN THỦ PHÒNG NGỪA DỰA TRÊN ĐƯỜNG LÂY TRUYỀN
update public.gstt_dm_bang_kiem bk set
  hanh_dong_khac_phuc_jsonb = $jsonb$[{"stt":1,"noi_dung":"Yêu cầu NVYT quay lại vùng đệm/ngoài cửa phòng để mang ĐÚNG và ĐỦ PTPH (Áo choàng, găng tay, N95...) trước khi tiếp tục vào phòng bệnh chăm sóc.","action_code":"ACT-200","la_stop_the_line":false},{"stt":2,"noi_dung":"Chặn ngay lập tức và yêu cầu NVYT tháo bỏ PTPH, vệ sinh tay nếu phát hiện họ đang mặc PTPH từ phòng cách ly bước ra ngoài hành lang hoặc chạm vào môi trường chung.","action_code":"ACT-200","la_stop_the_line":false},{"stt":3,"noi_dung":"Yêu cầu dán ngay Biển báo cách ly (Vàng/Cam/Xanh) ngoài cửa phòng; bố sung xe vật tư PTPH và cồn rửa tay ngay tại cửa.","action_code":"ACT-200","la_stop_the_line":false},{"stt":4,"noi_dung":"Trực tiếp nhắc nhở, giải thích và yêu cầu NB/người nhà đóng kín cửa phòng (đối với cách ly không khí) và mang khẩu trang y tế/vệ sinh hô hấp.","action_code":"ACT-100","la_stop_the_line":false},{"stt":5,"noi_dung":"Yêu cầu Khoa tiến hành khử khuẩn ngay các thiết bị y tế (ống nghe, huyết áp kế) vừa dùng chung cho NB cách ly tiếp xúc mà chưa được lau chùi.","action_code":"ACT-200","la_stop_the_line":false}]$jsonb$::jsonb,
