      ) order by (e->>'thu_tu_hien_thi')::int
    ) from jsonb_array_elements($jsonb$[{"lookup_code":"101_SYS","ten_hien_thi":"Thiếu vật tư, trang thiết bị tại điểm chăm sóc","mo_ta_chi_tiet":"Hết túi đựng tử thi chuyên dụng chống thấm, thiếu bông/gạc để bịt các lỗ tự nhiên, thiếu hộp kháng thủng sắc nhọn tại giường.","thu_tu_hien_thi":1},{"lookup_code":"102_SYS","ten_hien_thi":"Thiết kế môi trường/Công thái học bất hợp lý","mo_ta_chi_tiet":"Xe đẩy tử thi hỏng, không có nắp che/mái vòm che khuất; tủ bảo quản tại Nhà tang lễ không đạt chuẩn nhiệt độ.","thu_tu_hien_thi":2},{"lookup_code":"105_SYS","ten_hien_thi":"Lỗ hổng quy trình / Giao tiếp và bàn giao kém","mo_ta_chi_tiet":"Khoa lâm sàng không thông báo rõ tình trạng bệnh truyền nhiễm nguy hiểm của tử thi cho nhân viên Nhà tang lễ để có biện pháp phòng hộ tương ứng.","thu_tu_hien_thi":3},{"lookup_code":"201_HUM","ten_hien_thi":"Yếu tố Kỹ năng / Đào tạo chưa đạt","mo_ta_chi_tiet":"Làm sai kỹ thuật (không bịt kín các lỗ tự nhiên khiến dịch rỉ ra ngoài), không biết quy định bắt buộc phải lồng 2 túi (đóng gói kép) đối với ca bệnh truyền nhiễm nguy hiểm.","thu_tu_hien_thi":4},{"lookup_code":"203_HUM","ten_hien_thi":"Hành vi rủi ro \\- Thói quen đi tắt (Workaround)","mo_ta_chi_tiet":"Tháo gỡ các vật sắc nhọn (kim, dao) trên tử thi vội vàng gây rủi ro phơi nhiễm; không lau khử khuẩn xe đẩy tử thi sau khi sử dụng xong.","thu_tu_hien_thi":5},{"lookup_code":"204_HUM","ten_hien_thi":"Yếu tố Tâm sinh lý / Trạng thái cá nhân","mo_ta_chi_tiet":"Tâm lý e ngại, sợ hãi khi tiếp xúc với người chết dẫn đến thao tác vội vàng, quên vệ sinh tay sau khi tháo PTPH.","thu_tu_hien_thi":6},{"lookup_code":"304_CLI","ten_hien_thi":"Tình trạng giải phẫu / Bệnh lý đặc thù","mo_ta_chi_tiet":"Tử thi bị đa chấn thương nghiêm trọng, các vết thương hở phức tạp rỉ máu và dịch liên tục rất khó để bịt kín và làm sạch hoàn toàn; tử thi mang mầm bệnh tối nguy hiểm (nhóm A) tạo áp lực lây nhiễm lớn.","thu_tu_hien_thi":7}]$jsonb$::jsonb) e
    join public.sys_lookup_value l on l.category_type = 'NGUYEN_NHAN_LOI' and l.code = e->>'lookup_code')
