-- BM.17.01: BẢNG KIỂM GIÁM SÁT TUÂN THỦ ỨNG PHÓ BỆNH TRUYỀN NHIỄM TỐI NGUY HIỂM (COVID-19/EB
update public.gstt_dm_bang_kiem bk set
  hanh_dong_khac_phuc_jsonb = $jsonb$[{"stt":1,"noi_dung":"Đình chỉ (Stop the Line): Chặn ngay lập tức NVYT bước vào khu vực cách ly nếu phát hiện chưa mặc đúng/đủ PTPH hoặc chưa được Seal-check khẩu trang N95.","action_code":"ACT-400","la_stop_the_line":true},{"stt":2,"noi_dung":"\"Người giám sát\" lập tức can thiệp, yêu cầu NVYT dừng thao tác, thực hiện vệ sinh tay và điều chỉnh lại ngay tư thế nếu có nguy cơ chạm vào vùng bẩn trong quá trình cởi PTPH.","action_code":"ACT-200","la_stop_the_line":false},{"stt":3,"noi_dung":"Thiết lập ngay hàng rào vật lý, dán băng keo phân định rõ 3 vùng (Sạch \\- Đệm \\- Bẩn) và dán biển cảnh báo trước khu vực có người bệnh.","action_code":"ACT-200","la_stop_the_line":false},{"stt":4,"noi_dung":"Cung cấp ngay lập tức bộ PTPH đúng chuẩn (áo chống thấm, tấm che mặt, khẩu trang N95) cho kíp trực nếu đang sử dụng sai chuẩn PTPH.","action_code":"ACT-200","la_stop_the_line":false},{"stt":5,"noi_dung":"Hướng dẫn phong tỏa khu vực có tràn đổ máu/dịch tiết (chất nôn, máu) và yêu cầu đội vệ sinh môi trường chuyên trách xử lý bằng hóa chất khử khuẩn nồng độ cao.","action_code":"ACT-200","la_stop_the_line":false}]$jsonb$::jsonb,
  nguyen_nhan_cho_phep_jsonb = coalesce(
    (select jsonb_agg(
      jsonb_build_object(
        'lookup_id', l.id::text,
        'lookup_code', l.code,
        'ten_hien_thi', coalesce(e->>'ten_hien_thi', l.name),
        'mo_ta_chi_tiet', coalesce(e->>'mo_ta_chi_tiet', l.description),
        'thu_tu_hien_thi', (e->>'thu_tu_hien_thi')::int
      ) order by (e->>'thu_tu_hien_thi')::int
    ) from jsonb_array_elements($jsonb$[{"lookup_code":"101_SYS","ten_hien_thi":"Thiếu vật tư, trang thiết bị tại điểm chăm sóc","mo_ta_chi_tiet":"Không có sẵn PTPH cấp cao (PAPR, N95, bộ liền quần chống thấm, găng tay ống dài), thiếu hóa chất khử khuẩn chuyên dụng.","thu_tu_hien_thi":1},{"lookup_code":"102_SYS","ten_hien_thi":"Thiết kế môi trường/Công thái học bất hợp lý","mo_ta_chi_tiet":"Không có phòng áp lực âm (AIIR), buồng bệnh không đủ điều kiện chia 3 vùng (sạch-đệm-bẩn) rõ ràng khiến nguy cơ lây nhiễm chéo tăng cao.","thu_tu_hien_thi":2},{"lookup_code":"103_SYS","ten_hien_thi":"Quá tải công việc / Phân bổ nhân sự chưa phù hợp","mo_ta_chi_tiet":"Không bố trí đủ nhân sự để có \"Người giám sát\" (Trained observer) chuyên biệt đứng ngoài vùng đệm hướng dẫn mặc/cởi PTPH.","thu_tu_hien_thi":3},{"lookup_code":"105_SYS","ten_hien_thi":"Lỗ hổng quy trình / Thiếu y lệnh","mo_ta_chi_tiet":"Khoa Cấp cứu/Khám bệnh thiếu quy trình phân luồng, sàng lọc dịch tễ từ cửa, khiến NB xâm nhập sâu vào hệ thống Bệnh viện mới được phát hiện.","thu_tu_hien_thi":4},{"lookup_code":"201_HUM","ten_hien_thi":"Yếu tố Kỹ năng / Đào tạo chưa đạt","mo_ta_chi_tiet":"NVYT thao tác cởi PTPH sai trình tự (VD: tháo khẩu trang trước khi tháo áo choàng), chạm tay vào mặt ngoài PTPH gây phơi nhiễm cho bản thân.","thu_tu_hien_thi":5},{"lookup_code":"203_HUM","ten_hien_thi":"Hành vi rủi ro \\- Thói quen đi tắt (Workaround)","mo_ta_chi_tiet":"Tự ý vào phòng cách ly hoặc tự cởi PTPH một mình mà không có sự hiện diện của Người giám sát hỗ trợ đọc bảng kiểm.","thu_tu_hien_thi":6},{"lookup_code":"204_HUM","ten_hien_thi":"Yếu tố Tâm sinh lý / Trạng thái cá nhân","mo_ta_chi_tiet":"NVYT hoảng loạn, sợ hãi hoặc căng thẳng tâm lý tột độ khi đối mặt với ca bệnh Ebola/COVID-19 nặng, dẫn đến thao tác chệch choạc, quên vệ sinh tay giữa các bước cởi đồ.","thu_tu_hien_thi":7},{"lookup_code":"301_CLI","ten_hien_thi":"Tình huống cấp cứu khẩn cấp","mo_ta_chi_tiet":"NB đột ngột ngừng tuần hoàn, suy hô hấp cấp, NVYT lao vào cấp cứu/đặt ống nội khí quản ngay lập tức mà không kịp chờ mặc đầy đủ bộ PTPH cấp cao.","thu_tu_hien_thi":8},{"lookup_code":"302_CLI","ten_hien_thi":"Yếu tố tâm lý / Hành vi của người bệnh","mo_ta_chi_tiet":"NB vật vã, kích thích, nôn ói/xuất huyết ồ ạt (Ebola), từ chối đeo khẩu trang làm văng bắn lượng lớn máu/dịch tiết ra môi trường xung quanh.","thu_tu_hien_thi":9}]$jsonb$::jsonb) e
    join public.sys_lookup_value l on l.category_type = 'NGUYEN_NHAN_LOI' and l.code = e->>'lookup_code')
    , '[]'::jsonb)
where bk.ma_bk = 'BM.17.01';

-- BM.18.02: Bảng Kiểm Giám Sát Làm Sạch Dụng Cụ Tái Sử Dụng
update public.gstt_dm_bang_kiem bk set
  hanh_dong_khac_phuc_jsonb = $jsonb$[{"stt":1,"noi_dung":"Đình chỉ và Yêu cầu làm lại: Trả lại ngay dụng cụ bẩn (còn sót vết máu, mảng bám, chưa khô) để ngâm Enzyme và cọ rửa lại từ đầu.","action_code":"ACT-400","la_stop_the_line":true},{"stt":2,"noi_dung":"Cảnh báo và chấn chỉnh ngay lập tức hành vi cọ rửa dụng cụ trên mặt nước, yêu cầu nhân viên dìm ngập tay và dụng cụ dưới nước để bảo vệ hô hấp và niêm mạc.","action_code":"ACT-200","la_stop_the_line":false},{"stt":3,"noi_dung":"Yêu cầu NVYT mang bổ sung ngay kính bảo hộ/tấm che mặt và tạp dề chống thấm trước khi tiếp tục công việc tại khu bẩn CSSD.","action_code":"ACT-200","la_stop_the_line":false},{"stt":4,"noi_dung":"Phản hồi trực tiếp cho ĐD Trưởng khoa lâm sàng/Phòng mổ nếu phát hiện bộ dụng cụ bị ngâm sai quy định trong dung dịch NaCl 0.9% hoặc để khô két máu.","action_code":"ACT-200","la_stop_the_line":false},{"stt":5,"noi_dung":"Cấp phát bổ sung khẩn cấp các loại chổi cọ nòng phù hợp với kích thước lỗ (lumen) của ống hút/trocar.","action_code":"ACT-300","la_stop_the_line":false}]$jsonb$::jsonb,
  nguyen_nhan_cho_phep_jsonb = coalesce(
    (select jsonb_agg(
      jsonb_build_object(
        'lookup_id', l.id::text,
        'lookup_code', l.code,
        'ten_hien_thi', coalesce(e->>'ten_hien_thi', l.name),
        'mo_ta_chi_tiet', coalesce(e->>'mo_ta_chi_tiet', l.description),
        'thu_tu_hien_thi', (e->>'thu_tu_hien_thi')::int
      ) order by (e->>'thu_tu_hien_thi')::int
    ) from jsonb_array_elements($jsonb$[{"lookup_code":"101_SYS","ten_hien_thi":"Thiếu vật tư, trang thiết bị tại điểm chăm sóc","mo_ta_chi_tiet":"Thiếu hóa chất Enzyme, thiếu chổi cọ nòng đúng kích cỡ lumen, thiếu tạp dề/kính bảo hộ cho nhân viên khu bẩn, hết súng khí nén.","thu_tu_hien_thi":1},{"lookup_code":"102_SYS","ten_hien_thi":"Thiết kế môi trường/Công thái học bất hợp lý","mo_ta_chi_tiet":"Bồn rửa quá nông gây văng bắn khi cọ rửa, hệ thống nước không có van chỉnh nhiệt độ ấm 30-45°C.","thu_tu_hien_thi":2},{"lookup_code":"103_SYS","ten_hien_thi":"Quá tải công việc / Phân bổ nhân sự chưa phù hợp","mo_ta_chi_tiet":"Lượng dụng cụ đổ về từ phòng mổ quá lớn vào cuối ca, áp lực xoay vòng (turnover) nhanh khiến nhân viên phải rửa vội, bỏ qua thời gian ngâm đủ 15 phút.","thu_tu_hien_thi":3},{"lookup_code":"104_SYS","ten_hien_thi":"Lỗi thiết bị kỹ thuật / Hỏng hóc máy móc","mo_ta_chi_tiet":"Máy rửa sóng siêu âm hỏng, súng bơm rửa áp lực nước bị lỗi, hệ thống lọc nước RO cấp cho bồn tráng cuối bị tắc.","thu_tu_hien_thi":4},{"lookup_code":"201_HUM","ten_hien_thi":"Yếu tố Kỹ năng / Đào tạo chưa đạt","mo_ta_chi_tiet":"Làm sai kỹ thuật (cọ rửa dụng cụ ngay trên mặt nước làm phát tán khí dung lây nhiễm, pha hóa chất Enzyme bằng nước quá nóng làm chết men hoặc nước lạnh làm giảm tác dụng).","thu_tu_hien_thi":5},{"lookup_code":"203_HUM","ten_hien_thi":"Hành vi rủi ro \\- Thói quen đi tắt (Workaround)","mo_ta_chi_tiet":"Rút ngắn thời gian ngâm Enzyme, không tháo rời các khớp nối của dụng cụ khi rửa, không dùng chổi cọ vào lòng ống.","thu_tu_hien_thi":6},{"lookup_code":"204_HUM","ten_hien_thi":"Yếu tố Tâm sinh lý / Trạng thái cá nhân","mo_ta_chi_tiet":"Mất tập trung, quan sát kém do mệt mỏi dẫn đến bỏ sót vết máu/mô ở các khe kẽ răng cưa (VD: kẹp phẫu tích) khi soi dưới kính lúp.","thu_tu_hien_thi":7},{"lookup_code":"301_CLI","ten_hien_thi":"Tình huống cấp cứu khẩn cấp","mo_ta_chi_tiet":"Khoa lâm sàng/Phòng mổ cấp cứu liên tục, không kịp thời gian xử lý sơ bộ (lau máu thô, giữ ẩm) ngay tại bàn mổ, khiến máu và mô khô két chặt vào khe kẽ dụng cụ trước khi chuyển xuống CSSD.","thu_tu_hien_thi":8}]$jsonb$::jsonb) e
    join public.sys_lookup_value l on l.category_type = 'NGUYEN_NHAN_LOI' and l.code = e->>'lookup_code')
    , '[]'::jsonb)
where bk.ma_bk = 'BM.18.02';

-- BM.19.01: BẢNG KIỂM GIÁM SÁT TUÂN THỦ QUY TRÌNH KHỬ KHUẨN MỨC ĐỘ CAO
update public.gstt_dm_bang_kiem bk set
  hanh_dong_khac_phuc_jsonb = $jsonb$[{"stt":1,"noi_dung":"Đình chỉ quy trình: Yêu cầu dừng ngâm hóa chất và gửi bảo trì ngay lập tức nếu phát hiện ống soi thất bại trong bài kiểm tra rò rỉ (leak test).","action_code":"ACT-400","la_stop_the_line":true},{"stt":2,"noi_dung":"Bắt buộc đổ bỏ và thay mới chậu hóa chất KKMĐC nếu kiểm tra nồng độ bằng que thử (MEC) không đạt tiêu chuẩn (chuyển màu không hoàn toàn).","action_code":"ACT-200","la_stop_the_line":false},{"stt":3,"noi_dung":"Yêu cầu nhân viên làm lại quy trình từ bước cọ rửa bằng Enzyme nếu phát hiện vẫn còn cặn bẩn/máu tại các khe kẽ, van hoặc trên đầu bàn chải cọ.","action_code":"ACT-200","la_stop_the_line":false},{"stt":4,"noi_dung":"Nhắc nhở và yêu cầu NVYT mang bổ sung ngay PTPH (tạp dề chống thấm, găng tay kháng hóa chất, kính/tấm che mặt) trước khi tiếp tục thao tác với hóa chất độc hại.","action_code":"ACT-100","la_stop_the_line":false},{"stt":5,"noi_dung":"Kích hoạt quy trình thu hồi dụng cụ (Recall) nếu phát hiện thiết bị đã được đem ra sử dụng nhưng chu trình KKMĐC trước đó vi phạm thời gian ngâm hoặc hóa chất đã mất tác dụng.","action_code":"ACT-200","la_stop_the_line":false}]$jsonb$::jsonb,
  nguyen_nhan_cho_phep_jsonb = coalesce(
    (select jsonb_agg(
      jsonb_build_object(
        'lookup_id', l.id::text,
        'lookup_code', l.code,
        'ten_hien_thi', coalesce(e->>'ten_hien_thi', l.name),
        'mo_ta_chi_tiet', coalesce(e->>'mo_ta_chi_tiet', l.description),
        'thu_tu_hien_thi', (e->>'thu_tu_hien_thi')::int
      ) order by (e->>'thu_tu_hien_thi')::int
    ) from jsonb_array_elements($jsonb$[{"lookup_code":"101_SYS","ten_hien_thi":"Thiếu vật tư, trang thiết bị tại điểm chăm sóc","mo_ta_chi_tiet":"Hết que thử MEC, thiếu bàn chải nòng đúng kích cỡ lumen, hết cồn 70-90% để tráng ống, thiếu găng tay dài kháng hóa chất cho nhân viên.","thu_tu_hien_thi":1},{"lookup_code":"102_SYS","ten_hien_thi":"Thiết kế môi trường/Công thái học bất hợp lý","mo_ta_chi_tiet":"Bồn rửa quá nhỏ không thể ngâm ngập và duỗi thẳng ống soi, hệ thống hút mùi/thông khí hỏng khiến NVYT không thể đứng lâu tại khu vực ngâm KKMĐC, bồn ngâm không có nắp đậy đậy kín.","thu_tu_hien_thi":2},{"lookup_code":"103_SYS","ten_hien_thi":"Quá tải công việc / Phân bổ nhân sự chưa phù hợp","mo_ta_chi_tiet":"Lượng người bệnh nội soi quá đông, áp lực quay vòng dụng cụ (turnover) nhanh khiến nhân viên vội vã, rút ngắn thời gian làm sạch hoặc thời gian ngâm KKMĐC.","thu_tu_hien_thi":3},{"lookup_code":"104_SYS","ten_hien_thi":"Lỗi thiết bị kỹ thuật / Hỏng hóc máy móc","mo_ta_chi_tiet":"Máy rửa nội soi tự động (AER) bị lỗi kết nối kênh, súng xịt khí nén y tế hỏng, tủ sấy/tủ bảo quản treo dọc ống soi bị hỏng quạt thông khí.","thu_tu_hien_thi":4},{"lookup_code":"201_HUM","ten_hien_thi":"Yếu tố Kỹ năng / Đào tạo chưa đạt","mo_ta_chi_tiet":"NVYT không biết cách thực hiện kiểm tra rò rỉ (leak test), pha sai tỷ lệ hóa chất enzyme, hoặc sử dụng sai kích cỡ bàn chải nòng khiến kênh không được cọ sạch.","thu_tu_hien_thi":5},{"lookup_code":"203_HUM","ten_hien_thi":"Hành vi rủi ro \\- Thói quen đi tắt (Workaround)","mo_ta_chi_tiet":"Cố tình bỏ qua bước test MEC đầu ngày, không tráng cồn và thổi khí nén vào các kênh để làm khô trước khi cất, không tháo rời các van/nút chặn khi cọ rửa.","thu_tu_hien_thi":6},{"lookup_code":"204_HUM","ten_hien_thi":"Yếu tố Tâm sinh lý / Trạng thái cá nhân","mo_ta_chi_tiet":"Quên thay hóa chất KKMĐC khi que thử MEC báo không đạt, quên bơm hóa chất lấp đầy lòng ống do mất tập trung trong ca làm việc liên tục.","thu_tu_hien_thi":7},{"lookup_code":"301_CLI","ten_hien_thi":"Tình huống cấp cứu khẩn cấp","mo_ta_chi_tiet":"Tình huống cấp cứu cần ống soi phế quản/dạ dày ngay lập tức (VD: xuất huyết tiêu hóa ồ ạt, đặt nội khí quản khó) nhưng khoa không có ống dự phòng, buộc phải lấy ống đang xử lý dở dang (chưa hoàn tất bước làm khô).","thu_tu_hien_thi":8}]$jsonb$::jsonb) e
