-- BM.24.02: Bảng Kiểm Giám Sát Phòng Ngừa Nhiễm Khuẩn Vết Mổ
update public.gstt_dm_bang_kiem bk set
  hanh_dong_khac_phuc_jsonb = $jsonb$[{"stt":1,"noi_dung":"Đình chỉ thủ thuật (Stop the Line): Yêu cầu kíp phẫu thuật dừng việc rạch da hoặc dùng dao điện nếu phát hiện dung dịch sát khuẩn da (đặc biệt là cồn) chưa khô hoàn toàn [6].","action_code":"ACT-400","la_stop_the_line":true},{"stt":2,"noi_dung":"Đình chỉ ngay việc sử dụng dao cạo lông vũ để dọn lông vùng mổ; yêu cầu đổi sang dùng tông đơ điện hoặc bỏ qua bước cạo lông nếu không ảnh hưởng tới phẫu trường [6].","action_code":"ACT-400","la_stop_the_line":true},{"stt":3,"noi_dung":"Nhắc nhở Bác sĩ Gây mê/Điều dưỡng kiểm tra và bổ sung liều Kháng sinh dự phòng ngay lập tức nếu phát hiện ca mổ đã kéo dài hơn dự kiến [6].","action_code":"ACT-100","la_stop_the_line":false},{"stt":4,"noi_dung":"Yêu cầu người không có nhiệm vụ ra ngoài và đóng kín ngay cửa phòng mổ để đảm bảo áp suất dương [6].","action_code":"ACT-200","la_stop_the_line":false},{"stt":5,"noi_dung":"Yêu cầu Điều dưỡng tại khoa Hồi sức/Ngoại khoa thay ngay đôi găng tay vô khuẩn mới và sử dụng bộ dụng cụ vô khuẩn nếu quan sát thấy vi phạm kỹ thuật khi đang thay băng vết mổ [6].","action_code":"ACT-200","la_stop_the_line":false}]$jsonb$::jsonb,
  nguyen_nhan_cho_phep_jsonb = coalesce(
    (select jsonb_agg(
      jsonb_build_object(
        'lookup_id', l.id::text,
        'lookup_code', l.code,
        'ten_hien_thi', coalesce(e->>'ten_hien_thi', l.name),
        'mo_ta_chi_tiet', coalesce(e->>'mo_ta_chi_tiet', l.description),
        'thu_tu_hien_thi', (e->>'thu_tu_hien_thi')::int
      ) order by (e->>'thu_tu_hien_thi')::int
    ) from jsonb_array_elements($jsonb$[{"lookup_code":"101_SYS","ten_hien_thi":"Thiếu vật tư, trang thiết bị tại điểm chăm sóc","mo_ta_chi_tiet":"Không có sẵn tông đơ chuyên dụng (buộc phải dùng dao cạo), thiếu dung dịch sát khuẩn da chứa cồn, thiếu băng gạc vô khuẩn tại xe thay băng [6].","thu_tu_hien_thi":1},{"lookup_code":"102_SYS","ten_hien_thi":"Thiết kế môi trường/Công thái học bất hợp lý","mo_ta_chi_tiet":"Hệ thống thông khí phòng mổ (HVAC) hỏng không đảm bảo áp suất dương, cửa phòng mổ bị lỗi không thể đóng kín tự động [6].","thu_tu_hien_thi":2},{"lookup_code":"103_SYS","ten_hien_thi":"Quá tải công việc / Phân bổ nhân sự chưa phù hợp","mo_ta_chi_tiet":"Lịch mổ quá dày đặc khiến kíp phẫu thuật không đủ thời gian thực hiện vệ sinh tay ngoại khoa đúng chuẩn, nhân viên chạy ngoài phải đi lại liên tục lấy thêm vật tư [6].","thu_tu_hien_thi":3},{"lookup_code":"105_SYS","ten_hien_thi":"Lỗ hổng quy trình / Thiếu y lệnh","mo_ta_chi_tiet":"Không có quy trình nhắc nhở (như bảng kiểm Time-out) khiến bác sĩ quên y lệnh tiêm Kháng sinh dự phòng (KSDP) đúng khung giờ 60-120 phút trước khi rạch da [6].","thu_tu_hien_thi":4},{"lookup_code":"201_HUM","ten_hien_thi":"Yếu tố Kỹ năng / Đào tạo chưa đạt","mo_ta_chi_tiet":"NVYT thực hiện sai kỹ thuật sát khuẩn da vùng mổ, hoặc chưa chờ cồn khô hoàn toàn đã tiến hành rạch da hoặc sử dụng dao điện (nguy cơ cháy nổ và giảm tác dụng diệt khuẩn) [6].","thu_tu_hien_thi":5},{"lookup_code":"203_HUM","ten_hien_thi":"Hành vi rủi ro \\- Thói quen đi tắt (Workaround)","mo_ta_chi_tiet":"Cố tình bỏ qua các bước trong Bảng kiểm An toàn phẫu thuật (Time-out); tùy tiện mở cửa phòng mổ hoặc đi lại giao lưu trong lúc phẫu thuật; thay băng vết mổ hậu phẫu nhưng chỉ dùng găng sạch thay vì găng vô khuẩn [6].","thu_tu_hien_thi":6},{"lookup_code":"204_HUM","ten_hien_thi":"Yếu tố Tâm sinh lý / Trạng thái cá nhân","mo_ta_chi_tiet":"Bác sĩ Gây mê/Phẫu thuật viên quên chỉ định bổ sung liều KSDP khi ca mổ kéo dài do mất tập trung vào quá trình xử trí phẫu thuật phức tạp [6].","thu_tu_hien_thi":7},{"lookup_code":"301_CLI","ten_hien_thi":"Tình huống cấp cứu khẩn cấp","mo_ta_chi_tiet":"Bệnh nhân sốc đa chấn thương, vỡ tạng cần mổ tối khẩn cấp để cứu mạng, kíp mổ không có đủ thời gian để chờ dung dịch sát khuẩn khô, tắm trước mổ hay tiêm KSDP đúng khung giờ tiêu chuẩn [6].","thu_tu_hien_thi":8},{"lookup_code":"304_CLI","ten_hien_thi":"Tình trạng giải phẫu / Bệnh lý đặc thù","mo_ta_chi_tiet":"Người bệnh béo phì, đái tháo đường khó kiểm soát đường huyết (\\<200 mg/dL), hoặc có vết thương hở, rách nát da diện rộng từ trước khó đảm bảo sát khuẩn vô trùng [6].","thu_tu_hien_thi":9}]$jsonb$::jsonb) e
    join public.sys_lookup_value l on l.category_type = 'NGUYEN_NHAN_LOI' and l.code = e->>'lookup_code')
    , '[]'::jsonb)
where bk.ma_bk = 'BM.24.02';

-- BM.25.01: BẢNG KIỂM GIÁM SÁT TUÂN THỦ GÓI AN TOÀN ĐẶT ĐƯỜNG TRUYỀN TĨNH MẠCH TRUNG TÂM (IN
update public.gstt_dm_bang_kiem bk set
  hanh_dong_khac_phuc_jsonb = $jsonb$[{"stt":1,"noi_dung":"Đình chỉ thủ thuật (Stop the Line): Nhắc nhở và yêu cầu Bác sĩ dừng thao tác ngay lập tức nếu chưa mang đủ hàng rào vô khuẩn tối đa (áo choàng vô khuẩn, săng lớn) hoặc chưa chờ cồn sát khuẩn khô.","action_code":"ACT-400","la_stop_the_line":true},{"stt":2,"noi_dung":"Yêu cầu Bác sĩ thay ngay găng tay vô khuẩn mới hoặc thay săng trải bàn mới nếu quan sát thấy găng tay/săng vừa bị chạm vào vật không vô khuẩn.","action_code":"ACT-200","la_stop_the_line":false},{"stt":3,"noi_dung":"Yêu cầu Điều dưỡng phụ khẩn cấp đội mũ trùm tóc và mang khẩu trang y tế trước khi tiếp tục đứng hỗ trợ tại trường phẫu thuật.","action_code":"ACT-200","la_stop_the_line":false},{"stt":4,"noi_dung":"Ghi chú cảnh báo vào hồ sơ bệnh án: Yêu cầu đánh giá rút CVC sớm hoặc chuyển đường truyền khác trong vòng 24-48 giờ tới do quá trình đặt cấp cứu không đảm bảo tuyệt đối kỹ thuật vô khuẩn.","action_code":"ACT-200","la_stop_the_line":false}]$jsonb$::jsonb,
  nguyen_nhan_cho_phep_jsonb = coalesce(
    (select jsonb_agg(
      jsonb_build_object(
        'lookup_id', l.id::text,
        'lookup_code', l.code,
        'ten_hien_thi', coalesce(e->>'ten_hien_thi', l.name),
        'mo_ta_chi_tiet', coalesce(e->>'mo_ta_chi_tiet', l.description),
        'thu_tu_hien_thi', (e->>'thu_tu_hien_thi')::int
      ) order by (e->>'thu_tu_hien_thi')::int
    ) from jsonb_array_elements($jsonb$[{"lookup_code":"201_HUM","ten_hien_thi":"Yếu tố Kỹ năng / Đào tạo chưa đạt","mo_ta_chi_tiet":"Thực hiện sai kỹ thuật vô khuẩn (VD: Sát khuẩn da chưa đủ thời gian, chưa chờ cồn khô đã tiến hành chọc kim, trải săng không đủ che phủ toàn thân).","thu_tu_hien_thi":1},{"lookup_code":"203_HUM","ten_hien_thi":"Hành vi rủi ro \\- Thói quen đi tắt (Workaround)","mo_ta_chi_tiet":"Bỏ qua bước mặc áo choàng vô khuẩn hoặc người phụ không đội mũ/đeo khẩu trang vì nghĩ rằng \"chỉ là thủ thuật làm nhanh\".","thu_tu_hien_thi":2},{"lookup_code":"204_HUM","ten_hien_thi":"Yếu tố Tâm sinh lý / Trạng thái cá nhân","mo_ta_chi_tiet":"Mất tập trung làm tạp nhiễm trường vô khuẩn (VD: Vô tình để tay đang mang găng vô khuẩn chạm vào giường bệnh hoặc vùng da chưa sát khuẩn).","thu_tu_hien_thi":3},{"lookup_code":"301_CLI","ten_hien_thi":"Tình huống cấp cứu khẩn cấp","mo_ta_chi_tiet":"Bệnh nhân ngừng tuần hoàn, sốc mất máu cần thiết lập đường truyền tĩnh mạch trung tâm tối khẩn cấp để cứu mạng, không có đủ thời gian áp dụng toàn bộ hàng rào vô khuẩn tối đa.","thu_tu_hien_thi":4},{"lookup_code":"302_CLI","ten_hien_thi":"Yếu tố tâm lý / Hành vi của người bệnh","mo_ta_chi_tiet":"Người bệnh không hợp tác, mê sảng, vật vã, giãy giụa làm rách/tuột săng vô khuẩn hoặc gây tạp nhiễm vùng chọc kim trong lúc bác sĩ đang thao tác.","thu_tu_hien_thi":5},{"lookup_code":"304_CLI","ten_hien_thi":"Tình trạng giải phẫu / Bệnh lý đặc thù","mo_ta_chi_tiet":"Cơ địa người bệnh béo phì, phù nề, sốc giảm thể tích làm ven xẹp, khó xác định mốc giải phẫu khiến thao tác chọc kim phải thực hiện nhiều lần, kéo dài thời gian, làm tăng nguy cơ tạp nhiễm.","thu_tu_hien_thi":6}]$jsonb$::jsonb) e
    join public.sys_lookup_value l on l.category_type = 'NGUYEN_NHAN_LOI' and l.code = e->>'lookup_code')
    , '[]'::jsonb)
