-- BM.25.03: BẢNG KIỂM GIÁM SÁT TUÂN THỦ GÓI CHĂM SÓC VÀ DUY TRÌ ĐƯỜNG TRUYỀN (MAINTENANCE BU
update public.gstt_dm_bang_kiem bk set
  hanh_dong_khac_phuc_jsonb = $jsonb$[{"stt":1,"noi_dung":"Đình chỉ thao tác: Yêu cầu Điều dưỡng dừng ngay việc bơm thuốc, bắt buộc dùng miếng cồn mới chà xát cổng nối đủ 15 giây và chờ khô nếu phát hiện bỏ sót bước này.","action_code":"ACT-400","la_stop_the_line":true},{"stt":2,"noi_dung":"Yêu cầu chuẩn bị dụng cụ và thay ngay băng dán CVC mới với kỹ thuật vô khuẩn nếu quan sát thấy băng dán hiện tại bị ẩm ướt, đọng máu hoặc bong mép.","action_code":"ACT-200","la_stop_the_line":false},{"stt":3,"noi_dung":"Nhắc nhở và yêu cầu Bác sĩ bổ sung ngay đánh giá y lệnh Rút hoặc Tiếp tục lưu CVC vào hồ sơ bệnh án của ngày hiện tại.","action_code":"ACT-100","la_stop_the_line":false},{"stt":4,"noi_dung":"Yêu cầu tháo bỏ và thay mới hệ thống dây truyền dịch, chạc ba ngay lập tức nếu phát hiện đã quá hạn sử dụng (quá 96h với dịch thường/quá 24h với máu) hoặc không dán nhãn theo dõi.","action_code":"ACT-200","la_stop_the_line":false},{"stt":5,"noi_dung":"Cảnh báo NVYT về việc vệ sinh tay ngay lập tức nếu họ vừa tiếp xúc với môi trường xung quanh trước khi chạm vào catheter của người bệnh.","action_code":"ACT-200","la_stop_the_line":false},{"stt":6,"noi_dung":"Cảnh báo và yêu cầu treo ngay túi dẫn lưu THẤP HƠN bàng quang và móc cố định vào khung giường nếu phát hiện túi đang để trên bụng NB hoặc nằm dưới sàn nhà [2, 5].","action_code":"ACT-200","la_stop_the_line":false},{"stt":7,"noi_dung":"Yêu cầu Điều dưỡng/Hộ lý xả ngay túi nước tiểu nếu quan sát thấy túi đã đầy trên 2/3; hướng dẫn lại tại chỗ việc không để vòi xả chạm thành bình hứng [2, 6].","action_code":"ACT-100","la_stop_the_line":false},{"stt":8,"noi_dung":"Cung cấp ngay bình đong nước tiểu sạch, có dán tên/số giường riêng biệt cho NB nếu phát hiện điều dưỡng đang sử dụng chung một bình hứng cho nhiều giường [2, 4, 6].","action_code":"ACT-200","la_stop_the_line":false},{"stt":9,"noi_dung":"Đình chỉ thao tác và nhắc nhở nghiêm khắc nếu phát hiện Điều dưỡng cố tình tháo rời chốt nối giữa ống thông và dây dẫn (phá vỡ hệ thống kín) để lấy nước tiểu hoặc thay quần áo [2, 3, 6].","action_code":"ACT-400","la_stop_the_line":true},{"stt":10,"noi_dung":"Phản hồi trực tiếp yêu cầu Bác sĩ ghi bổ sung y lệnh đánh giá Rút hoặc Tiếp tục lưu ống thông tiểu vào hồ sơ bệnh án của ngày hiện tại [2, 3, 6].","action_code":"ACT-200","la_stop_the_line":false}]$jsonb$::jsonb,
  nguyen_nhan_cho_phep_jsonb = coalesce(
    (select jsonb_agg(
      jsonb_build_object(
        'lookup_id', l.id::text,
        'lookup_code', l.code,
        'ten_hien_thi', coalesce(e->>'ten_hien_thi', l.name),
        'mo_ta_chi_tiet', coalesce(e->>'mo_ta_chi_tiet', l.description),
        'thu_tu_hien_thi', (e->>'thu_tu_hien_thi')::int
      ) order by (e->>'thu_tu_hien_thi')::int
    ) from jsonb_array_elements($jsonb$[{"lookup_code":"101_SYS","ten_hien_thi":"Thiếu vật tư, trang thiết bị tại điểm chăm sóc","mo_ta_chi_tiet":"Không có sẵn bình đong/hứng nước tiểu riêng biệt cho từng người bệnh, thiếu xà phòng/khăn sạch để vệ sinh vùng sinh dục hàng ngày [2, 4, 6].","thu_tu_hien_thi":1},{"lookup_code":"103_SYS","ten_hien_thi":"Quá tải công việc / Phân bổ nhân sự chưa phù hợp","mo_ta_chi_tiet":"Tỷ lệ bệnh nhân/điều dưỡng quá cao khiến NVYT không có đủ thời gian vệ sinh sinh dục đúng quy chuẩn hoặc xả túi dẫn lưu kịp thời trước khi đầy [2, 6].","thu_tu_hien_thi":2},{"lookup_code":"201_HUM","ten_hien_thi":"Yếu tố Kỹ năng / Đào tạo chưa đạt","mo_ta_chi_tiet":"Làm sai kỹ thuật xả nước tiểu (để vòi xả chạm trực tiếp vào bình hứng chung gây nhiễm khuẩn ngược dòng), hoặc lạm dụng dung dịch Povidone-Iodine để vệ sinh hàng ngày thay vì dùng xà phòng [2, 4, 6].","thu_tu_hien_thi":3},{"lookup_code":"203_HUM","ten_hien_thi":"Hành vi rủi ro \\- Thói quen đi tắt (Workaround)","mo_ta_chi_tiet":"Cố tình ngắt kết nối hệ thống kín giữa ống thông và dây dẫn để tiện di chuyển, tắm rửa cho người bệnh hoặc thay quần áo; lấy mẫu nước tiểu sai quy định trực tiếp từ túi dẫn lưu [2, 6].","thu_tu_hien_thi":4},{"lookup_code":"204_HUM","ten_hien_thi":"Yếu tố Tâm sinh lý / Trạng thái cá nhân","mo_ta_chi_tiet":"Quên vệ sinh tay trước/sau khi xả nước tiểu; quên treo túi lên móc giường khiến túi rớt chạm sàn nhà do vội vã trong ca trực [2, 6].","thu_tu_hien_thi":5},{"lookup_code":"301_CLI","ten_hien_thi":"Tình huống cấp cứu khẩn cấp","mo_ta_chi_tiet":"Người bệnh diễn biến nặng (ngừng tuần hoàn, sốc) cần bơm thuốc vận mạch tĩnh mạch khẩn cấp để cứu mạng, buộc NVYT phải bỏ qua bước sát khuẩn cổng nối 15 giây.","thu_tu_hien_thi":6},{"lookup_code":"302_CLI","ten_hien_thi":"Yếu tố tâm lý / Hành vi của người bệnh","mo_ta_chi_tiet":"Người bệnh mê sảng, vật vã, kích thích không hợp tác vô tình giật kéo làm lỏng các chốt kết nối của hệ thống dẫn lưu hoặc làm rớt túi nước tiểu xuống sàn [2, 6].","thu_tu_hien_thi":7},{"lookup_code":"105_SYS","ten_hien_thi":"Lỗ hổng quy trình / Thiếu y lệnh","mo_ta_chi_tiet":"Bác sĩ điều trị thiếu quy trình đánh giá lại (không có phiếu nhắc/reminder tự động trong HIS) dẫn đến việc \"bỏ quên\" ống thông lưu quá số ngày cần thiết [2, 6].","thu_tu_hien_thi":8},{"lookup_code":"304_CLI","ten_hien_thi":"Tình trạng giải phẫu / Bệnh lý đặc thù","mo_ta_chi_tiet":"Người bệnh xuất hiện tình trạng tắc nghẽn đặc thù (máu cục, cặn mủ bàng quang) buộc NVYT phải ngắt kết nối hệ thống kín để bơm rửa bàng quang cấp cứu [2].","thu_tu_hien_thi":9}]$jsonb$::jsonb) e
    join public.sys_lookup_value l on l.category_type = 'NGUYEN_NHAN_LOI' and l.code = e->>'lookup_code')
    , '[]'::jsonb)
where bk.ma_bk = 'BM.25.03';

-- BM.26.01: Bảng Kiểm Giám Sát Tuân Thủ Gói Phòng Ngừa Viêm Phổi Thở Máy
update public.gstt_dm_bang_kiem bk set
  hanh_dong_khac_phuc_jsonb = $jsonb$[{"stt":1,"noi_dung":"Yêu cầu Điều dưỡng lập tức điều chỉnh nâng đầu giường đạt $30^\\circ \\- 45^\\circ$ (nếu không có chống chỉ định y khoa) và đánh dấu góc nâng trên thành giường.","action_code":"ACT-200","la_stop_the_line":false},{"stt":2,"noi_dung":"Hướng dẫn lại tại chỗ (Coaching) kỹ thuật đổ nước đọng trong bẫy nước của dây máy thở đúng cách, tuyệt đối ngăn không để chảy ngược vào ống nội khí quản.","action_code":"ACT-100","la_stop_the_line":false},{"stt":3,"noi_dung":"Yêu cầu NVYT lấy bàn chải mềm thực hiện lại thao tác vệ sinh răng miệng cơ học nếu phát hiện chỉ dùng gạc lau qua loa bề mặt.","action_code":"ACT-200","la_stop_the_line":false},{"stt":4,"noi_dung":"Nhắc nhở trực tiếp và yêu cầu Bác sĩ bổ sung y lệnh đánh giá Thử nghiệm thức tỉnh tự phát (SAT) và cai máy (SBT) vào hồ sơ bệnh án của ngày hiện tại.","action_code":"ACT-100","la_stop_the_line":false},{"stt":5,"noi_dung":"Bổ sung khẩn cấp bộ dụng cụ chăm sóc răng miệng, ống hút đờm kín hoặc đồng hồ đo áp lực bóng chèn từ kho vật tư ra ngay tại đầu giường bệnh.","action_code":"ACT-300","la_stop_the_line":false}]$jsonb$::jsonb,
  nguyen_nhan_cho_phep_jsonb = coalesce(
    (select jsonb_agg(
      jsonb_build_object(
        'lookup_id', l.id::text,
        'lookup_code', l.code,
        'ten_hien_thi', coalesce(e->>'ten_hien_thi', l.name),
        'mo_ta_chi_tiet', coalesce(e->>'mo_ta_chi_tiet', l.description),
        'thu_tu_hien_thi', (e->>'thu_tu_hien_thi')::int
      ) order by (e->>'thu_tu_hien_thi')::int
    ) from jsonb_array_elements($jsonb$[{"lookup_code":"101_SYS","ten_hien_thi":"Thiếu vật tư, trang thiết bị tại điểm chăm sóc","mo_ta_chi_tiet":"Không có sẵn bàn chải đánh răng mềm chuyên dụng, thiếu dụng cụ đo áp lực bóng chèn (cuffometer) tại khoa, hết hệ thống hút đờm kín.","thu_tu_hien_thi":1},{"lookup_code":"103_SYS","ten_hien_thi":"Quá tải công việc / Phân bổ nhân sự chưa phù hợp","mo_ta_chi_tiet":"Tỷ lệ người bệnh thở máy/Điều dưỡng quá cao khiến NVYT không có đủ thời gian thực hiện chải răng cơ học đủ 2-3 lần/ngày hoặc không kịp đổ bẫy nước đọng liên tục.","thu_tu_hien_thi":2},{"lookup_code":"105_SYS","ten_hien_thi":"Lỗ hổng quy trình / Thiếu y lệnh","mo_ta_chi_tiet":"Bác sĩ điều trị thiếu y lệnh đánh giá SAT/SBT hàng ngày hoặc quy trình cai máy không được chuẩn hóa vào phiếu theo dõi lâm sàng.","thu_tu_hien_thi":3},{"lookup_code":"201_HUM","ten_hien_thi":"Yếu tố Kỹ năng / Đào tạo chưa đạt","mo_ta_chi_tiet":"Làm sai kỹ thuật (chỉ dùng gạc lau khoang miệng qua loa thay vì chải răng cơ học bằng bàn chải); thao tác đổ nước đọng trong bẫy nước dốc ngược làm dịch chảy ngược vào đường thở.","thu_tu_hien_thi":4},{"lookup_code":"203_HUM","ten_hien_thi":"Hành vi rủi ro \\- Thói quen đi tắt (Workaround)","mo_ta_chi_tiet":"Cố tình để đầu giường bằng phẳng ($0^\\circ$) vì ngại người bệnh trượt xuống phải kéo lên nhiều lần; hút đờm theo thói quen định kỳ thay vì theo chỉ định (nghe phổi, SpO2 giảm).","thu_tu_hien_thi":5},{"lookup_code":"204_HUM","ten_hien_thi":"Yếu tố Tâm sinh lý / Trạng thái cá nhân","mo_ta_chi_tiet":"Quên kiểm tra và quay lại điều chỉnh góc nâng đầu giường sau khi thay ga giường/lật trở người bệnh do vội vã.","thu_tu_hien_thi":6},{"lookup_code":"301_CLI","ten_hien_thi":"Tình huống cấp cứu khẩn cấp","mo_ta_chi_tiet":"Người bệnh đang trong tình trạng sốc, huyết động không ổn định buộc phải để đầu bằng hoặc đang cấp cứu nên không thể thực hiện đánh giá cai máy/vận động sớm.","thu_tu_hien_thi":7},{"lookup_code":"304_CLI","ten_hien_thi":"Tình trạng giải phẫu / Bệnh lý đặc thù","mo_ta_chi_tiet":"Người bệnh có chấn thương cột sống cổ, tổn thương/phẫu thuật vùng hàm mặt nghiêm trọng chống chỉ định việc nâng đầu cao $30-45^\\circ$ hoặc chải răng cơ học.","thu_tu_hien_thi":8}]$jsonb$::jsonb) e
    join public.sys_lookup_value l on l.category_type = 'NGUYEN_NHAN_LOI' and l.code = e->>'lookup_code')
    , '[]'::jsonb)
where bk.ma_bk = 'BM.26.01';

-- BM.27.01: BẢNG KIỂM GIÁM SÁT TUÂN THỦ GÓI AN TOÀN ĐẶT ỐNG THÔNG TIỂU (INSERTION BUNDLE \- 
update public.gstt_dm_bang_kiem bk set
  hanh_dong_khac_phuc_jsonb = $jsonb$[{"stt":1,"noi_dung":"Đình chỉ thủ thuật (Stop the Line): Yêu cầu Điều dưỡng dừng ngay thao tác, thay găng vô khuẩn mới và sử dụng ống thông tiểu mới nếu phát hiện đầu ống thông hoặc găng tay đã bị chạm/nhiễm bẩn vào môi trường xung quanh [3].","action_code":"ACT-400","la_stop_the_line":true},{"stt":2,"noi_dung":"Phản hồi trực tiếp với Bác sĩ điều trị để xem xét/hủy y lệnh nếu phát hiện chỉ định đặt thông tiểu không phù hợp (VD: đặt vì \"thuận tiện\" chăm sóc) và đề xuất sử dụng biện pháp thay thế (bỉm, ống bao dương vật) [3, 4].","action_code":"ACT-200","la_stop_the_line":false},{"stt":3,"noi_dung":"Yêu cầu thực hiện vệ sinh tay lại ngay lập tức nếu phát hiện nhân viên y tế bỏ sót bước này trước khi mang găng vô khuẩn.","action_code":"ACT-200","la_stop_the_line":false},{"stt":4,"noi_dung":"Hướng dẫn lại tại chỗ (Coaching) cách dán băng dính cố định ống thông đúng vị trí (mặt trong đùi đối với nữ/bụng dưới đối với nam) để chống giằng xé và tổn thương niệu đạo [3].","action_code":"ACT-100","la_stop_the_line":false},{"stt":5,"noi_dung":"Yêu cầu treo ngay túi dẫn lưu thấp hơn bàng quang, đảm bảo hệ thống dẫn lưu luôn kín và tuyệt đối không để túi chạm sàn [3].","action_code":"ACT-200","la_stop_the_line":false}]$jsonb$::jsonb,
  nguyen_nhan_cho_phep_jsonb = coalesce(
    (select jsonb_agg(
      jsonb_build_object(
        'lookup_id', l.id::text,
        'lookup_code', l.code,
        'ten_hien_thi', coalesce(e->>'ten_hien_thi', l.name),
        'mo_ta_chi_tiet', coalesce(e->>'mo_ta_chi_tiet', l.description),
        'thu_tu_hien_thi', (e->>'thu_tu_hien_thi')::int
      ) order by (e->>'thu_tu_hien_thi')::int
    ) from jsonb_array_elements($jsonb$[{"lookup_code":"201_HUM","ten_hien_thi":"Yếu tố Kỹ năng / Đào tạo chưa đạt","mo_ta_chi_tiet":"Vi phạm nguyên tắc vô khuẩn trong kỹ thuật (VD: mang găng không vô khuẩn, thao tác làm chạm đầu ống thông tiểu vào ga trải giường/vùng da chưa sát khuẩn trước khi đưa vào bàng quang) [3, 4].","thu_tu_hien_thi":1},{"lookup_code":"203_HUM","ten_hien_thi":"Hành vi rủi ro \\- Thói quen đi tắt (Workaround)","mo_ta_chi_tiet":"Ra y lệnh đặt ống thông tiểu vì lý do \"thuận tiện\" cho việc chăm sóc thay vì có chỉ định y khoa thực sự, hoặc bỏ qua bước sát khuẩn kỹ lỗ niệu đạo [1, 4].","thu_tu_hien_thi":2},{"lookup_code":"204_HUM","ten_hien_thi":"Yếu tố Tâm sinh lý / Trạng thái cá nhân","mo_ta_chi_tiet":"Quên thực hiện vệ sinh tay trước khi chuẩn bị dụng cụ và thao tác đặt do áp lực công việc, mất tập trung [1].","thu_tu_hien_thi":3},{"lookup_code":"301_CLI","ten_hien_thi":"Tình huống cấp cứu khẩn cấp","mo_ta_chi_tiet":"Người bệnh trong tình trạng sốc, đa chấn thương nguy kịch cần đặt ống thông tiểu khẩn cấp để theo dõi lượng nước tiểu liên tục, khiến việc tuân thủ tuyệt đối toàn bộ hàng rào vô khuẩn bị gián đoạn.","thu_tu_hien_thi":4},{"lookup_code":"302_CLI","ten_hien_thi":"Yếu tố tâm lý / Hành vi của người bệnh","mo_ta_chi_tiet":"Người bệnh không hợp tác, kích thích, mê sảng, vật vã giãy giụa làm rách găng tay vô khuẩn của nhân viên y tế hoặc làm tạp nhiễm vùng sinh dục vừa được sát khuẩn.","thu_tu_hien_thi":5},{"lookup_code":"304_CLI","ten_hien_thi":"Tình trạng giải phẫu / Bệnh lý đặc thù","mo_ta_chi_tiet":"Khó khăn khách quan từ cơ địa người bệnh (VD: phì đại tuyến tiền liệt, chít hẹp niệu đạo, dị dạng giải phẫu) khiến thao tác đưa ống thông vào bàng quang gặp khó khăn, phải thực hiện nhiều lần làm tăng nguy cơ nhiễm khuẩn.","thu_tu_hien_thi":6}]$jsonb$::jsonb) e
    join public.sys_lookup_value l on l.category_type = 'NGUYEN_NHAN_LOI' and l.code = e->>'lookup_code')
    , '[]'::jsonb)
where bk.ma_bk = 'BM.27.01';

-- BM.11.01: BẢNG KIỂM GIÁM SÁT TUÂN THỦ VỆ SINH MÔI TRƯỜNG BỀ MẶT
update public.gstt_dm_bang_kiem bk set
  hanh_dong_khac_phuc_jsonb = $jsonb$[{"stt":1,"noi_dung":"Cảnh báo và yêu cầu đổi ngay xô/giẻ lau nếu phát hiện nhân viên đang sử dụng sai quy định mã màu (đặc biệt khi dùng giẻ nhà vệ sinh lau khu vực điều trị).","action_code":"ACT-200","la_stop_the_line":false},{"stt":2,"noi_dung":"Đình chỉ thao tác quét khô trong buồng bệnh, yêu cầu nhân viên đổi sang sử dụng cây lau ẩm hoặc máy hút bụi có màng lọc HEPA.","action_code":"ACT-400","la_stop_the_line":true},{"stt":3,"noi_dung":"Yêu cầu đổ bỏ dung dịch hóa chất và pha lại ngay lập tức nếu kiểm tra thấy sai nồng độ quy định.","action_code":"ACT-200","la_stop_the_line":false},{"stt":4,"noi_dung":"Trực tiếp yêu cầu nhân viên vệ sinh/điều dưỡng lau lại các bề mặt tiếp xúc thường xuyên (tay nắm cửa, thành giường, monitor) nếu phát hiện vẫn còn bụi bẩn hoặc vết máu.","action_code":"ACT-200","la_stop_the_line":false},{"stt":5,"noi_dung":"Yêu cầu nhân viên vệ sinh lập tức đặt biển cảnh báo \"Sàn ướt/Trơn trượt\" trước khi tiếp tục công việc lau sàn.","action_code":"ACT-200","la_stop_the_line":false}]$jsonb$::jsonb,
  nguyen_nhan_cho_phep_jsonb = coalesce(
    (select jsonb_agg(
      jsonb_build_object(
        'lookup_id', l.id::text,
        'lookup_code', l.code,
        'ten_hien_thi', coalesce(e->>'ten_hien_thi', l.name),
        'mo_ta_chi_tiet', coalesce(e->>'mo_ta_chi_tiet', l.description),
        'thu_tu_hien_thi', (e->>'thu_tu_hien_thi')::int
      ) order by (e->>'thu_tu_hien_thi')::int
    ) from jsonb_array_elements($jsonb$[{"lookup_code":"101_SYS","ten_hien_thi":"Thiếu vật tư, trang thiết bị tại điểm chăm sóc","mo_ta_chi_tiet":"Hết giẻ lau đúng mã màu, hết hóa chất khử khuẩn, thiếu cốc đong hóa chất, xe làm vệ sinh bị hỏng hóc.","thu_tu_hien_thi":1},{"lookup_code":"103_SYS","ten_hien_thi":"Quá tải công việc / Phân bổ nhân sự chưa phù hợp","mo_ta_chi_tiet":"Diện tích khu vực làm sạch quá rộng, tỷ lệ nhân viên vệ sinh/số giường bệnh thấp khiến nhân viên phải làm nhanh, làm ẩu.","thu_tu_hien_thi":2},{"lookup_code":"105_SYS","ten_hien_thi":"Lỗ hổng quy trình / Thiếu y lệnh","mo_ta_chi_tiet":"Không phân định rõ ràng trách nhiệm lau bề mặt thiết bị máy móc (Monitor, máy thở) là của Nhân viên vệ sinh hay Điều dưỡng dẫn đến bỏ sót.","thu_tu_hien_thi":3},{"lookup_code":"106_SYS","ten_hien_thi":"Lỗi hệ thống thông tin / Giao tiếp và bàn giao kém","mo_ta_chi_tiet":"Khoa lâm sàng không thông báo cho nhân viên vệ sinh biết đây là phòng cách ly bệnh truyền nhiễm (Vùng Đỏ) để sử dụng đúng bộ dụng cụ và hóa chất tăng cường.","thu_tu_hien_thi":4},{"lookup_code":"201_HUM","ten_hien_thi":"Yếu tố Kỹ năng / Đào tạo chưa đạt","mo_ta_chi_tiet":"Nhân viên vệ sinh không biết cách pha hóa chất đúng tỷ lệ, lau sai kỹ thuật (lau xoáy tròn thay vì ziczac làm phát tán bụi trở lại).","thu_tu_hien_thi":5},{"lookup_code":"203_HUM","ten_hien_thi":"Hành vi rủi ro \\- Thói quen đi tắt (Workaround)","mo_ta_chi_tiet":"Tiện tay dùng sai mã màu giẻ lau (mang giẻ khu vực nhà vệ sinh ra lau bàn ăn), cố tình dùng chổi quét khô trong buồng bệnh để làm cho nhanh thay vì dùng cây lau ẩm, lười không đặt biển báo sàn ướt.","thu_tu_hien_thi":6},{"lookup_code":"204_HUM","ten_hien_thi":"Yếu tố Tâm sinh lý / Trạng thái cá nhân","mo_ta_chi_tiet":"Điều dưỡng quên lau khử khuẩn ống nghe, huyết áp kế giữa các lần khám bệnh nhân do vội vã, đông bệnh nhân.","thu_tu_hien_thi":7},{"lookup_code":"301_CLI","ten_hien_thi":"Tình huống cấp cứu khẩn cấp","mo_ta_chi_tiet":"Đang có tình huống cấp cứu hồi sức tại buồng bệnh, nhân viên vệ sinh không thể vào làm vệ sinh môi trường theo đúng lịch trình dự kiến.","thu_tu_hien_thi":8}]$jsonb$::jsonb) e
    join public.sys_lookup_value l on l.category_type = 'NGUYEN_NHAN_LOI' and l.code = e->>'lookup_code')
    , '[]'::jsonb)
where bk.ma_bk = 'BM.11.01';

-- BM.12.01: Bảng Kiểm Giám Sát Tuân Thủ Quản Lý Chất Thải Y Tế
update public.gstt_dm_bang_kiem bk set
  hanh_dong_khac_phuc_jsonb = $jsonb$[{"stt":1,"noi_dung":"Cảnh báo và yêu cầu nhân viên y tế/vệ sinh nhặt lại bằng kẹp/găng tay để phân loại lại nếu phát hiện vứt nhầm rác sinh hoạt vào thùng lây nhiễm (hoặc ngược lại).","action_code":"ACT-200","la_stop_the_line":false},{"stt":2,"noi_dung":"Đình chỉ thao tác thu gom và yêu cầu Nhân viên vệ sinh mang ngay găng tay cao su dày/tạp dề trước khi tiếp xúc với túi rác y tế.","action_code":"ACT-400","la_stop_the_line":true},{"stt":3,"noi_dung":"Cung cấp ngay hộp kháng thủng thay thế và yêu cầu đóng chốt khóa an toàn đối với hộp sắc nhọn đã đầy quá vạch 3/4.","action_code":"ACT-200","la_stop_the_line":false},{"stt":4,"noi_dung":"Báo cáo Trưởng khoa và lập biên bản sự cố cận kề (Near-miss) ngay lập tức nếu phát hiện có vật sắc nhọn/kim tiêm bị vứt lẫn trong túi nilon rác mềm.","action_code":"ACT-500","la_stop_the_line":false},{"stt":5,"noi_dung":"Tạm dừng xe vận chuyển rác nếu phát hiện xe không có nắp đậy hoặc đang làm rò rỉ nước rác ra hành lang; yêu cầu lau dọn khử khuẩn ngay vết rò rỉ.","action_code":"ACT-200","la_stop_the_line":false}]$jsonb$::jsonb,
  nguyen_nhan_cho_phep_jsonb = coalesce(
    (select jsonb_agg(
      jsonb_build_object(
        'lookup_id', l.id::text,
        'lookup_code', l.code,
        'ten_hien_thi', coalesce(e->>'ten_hien_thi', l.name),
        'mo_ta_chi_tiet', coalesce(e->>'mo_ta_chi_tiet', l.description),
