  hanh_dong_khac_phuc_jsonb = $jsonb$[{"stt":1,"noi_dung":"Đình chỉ thủ thuật (Stop the Line): Nhắc nhở và yêu cầu Bác sĩ dừng tay, chờ cồn sát khuẩn trên da bệnh nhân khô tự nhiên hoàn toàn trước khi tiến hành chọc mạch.","action_code":"ACT-400","la_stop_the_line":true},{"stt":2,"noi_dung":"Cảnh báo và yêu cầu Kỹ thuật viên hình ảnh lùi lại, thay mới ngay tấm bọc vô khuẩn máy C-arm hoặc săng trải bàn nếu phát hiện người không mặc đồ vô khuẩn vừa chạm vào.","action_code":"ACT-200","la_stop_the_line":false},{"stt":3,"noi_dung":"Yêu cầu nhân viên y tế lấy áo chì đang bị vứt/gấp trên ghế treo ngay lên giá thẳng đứng chuyên dụng để bảo vệ tính vẹn toàn của lõi chì.","action_code":"ACT-200","la_stop_the_line":false},{"stt":4,"noi_dung":"Cung cấp ngay khăn tẩm cồn/hóa chất và yêu cầu Điều dưỡng lau sạch vết máu bắn trên áo chì, thân máy C-arm hoặc trên sàn nhà trước khi nhận bệnh nhân tiếp theo.","action_code":"ACT-200","la_stop_the_line":false},{"stt":5,"noi_dung":"Yêu cầu đóng kín cửa phòng Cathlab và mời những người không có nhiệm vụ ra ngoài để bảo vệ áp suất và luồng khí vô khuẩn của phòng can thiệp.","action_code":"ACT-200","la_stop_the_line":false}]$jsonb$::jsonb,
  nguyen_nhan_cho_phep_jsonb = coalesce(
    (select jsonb_agg(
      jsonb_build_object(
        'lookup_id', l.id::text,
        'lookup_code', l.code,
        'ten_hien_thi', coalesce(e->>'ten_hien_thi', l.name),
        'mo_ta_chi_tiet', coalesce(e->>'mo_ta_chi_tiet', l.description),
        'thu_tu_hien_thi', (e->>'thu_tu_hien_thi')::int
      ) order by (e->>'thu_tu_hien_thi')::int
    ) from jsonb_array_elements($jsonb$[{"lookup_code":"101_SYS","ten_hien_thi":"Thiếu vật tư, trang thiết bị tại điểm chăm sóc","mo_ta_chi_tiet":"Thiếu bao nilon/săng vô khuẩn chuyên dụng để bọc máy C-arm; thiếu giá treo áo chì chịu lực dẫn đến nhân viên phải vắt tạm lên ghế/bàn; thiếu áo choàng vô khuẩn.","thu_tu_hien_thi":1},{"lookup_code":"102_SYS","ten_hien_thi":"Thiết kế môi trường/Công thái học bất hợp lý","mo_ta_chi_tiet":"Cửa phòng Cathlab hỏng cảm biến tự động, không khép kín được; hệ thống HVAC hỏng làm mất áp suất dương vô khuẩn.","thu_tu_hien_thi":2},{"lookup_code":"201_HUM","ten_hien_thi":"Yếu tố Kỹ năng / Đào tạo chưa đạt","mo_ta_chi_tiet":"Kỹ thuật viên hình ảnh hoặc Điều dưỡng chạy ngoài vô tình vươn tay qua phẫu trường hoặc chạm vào C-arm đã bọc vô khuẩn để chỉnh máy do thiếu ranh giới rõ ràng.","thu_tu_hien_thi":3},{"lookup_code":"203_HUM","ten_hien_thi":"Hành vi rủi ro \\- Thói quen đi tắt (Workaround)","mo_ta_chi_tiet":"Thói quen gấp đôi áo chì cất vào tủ cho gọn (làm gãy lõi chì chống tia X); lười không bọc vô khuẩn máy C-arm vì nghĩ \"ca làm nhanh\"; rạch da/chọc kim khi cồn sát khuẩn trên da bệnh nhân vẫn còn ướt sũng.","thu_tu_hien_thi":4},{"lookup_code":"204_HUM","ten_hien_thi":"Yếu tố Tâm sinh lý / Trạng thái cá nhân","mo_ta_chi_tiet":"Kíp can thiệp mệt mỏi, phân tâm nên quên lau khử khuẩn các vết máu bắn lên áo chì hoặc bề mặt thân máy sau khi kết thúc ca can thiệp căng thẳng.","thu_tu_hien_thi":5},{"lookup_code":"301_CLI","ten_hien_thi":"Tình huống cấp cứu khẩn cấp","mo_ta_chi_tiet":"Tình huống can thiệp Đột quỵ tối khẩn (lấy huyết khối) hoặc Nhồi máu cơ tim cấp (STEMI) đe dọa tính mạng, kíp trực không có đủ thời gian để bọc C-arm kỹ lưỡng hoặc chờ cồn sát khuẩn khô đủ thời gian tiêu chuẩn.","thu_tu_hien_thi":6}]$jsonb$::jsonb) e
    join public.sys_lookup_value l on l.category_type = 'NGUYEN_NHAN_LOI' and l.code = e->>'lookup_code')
    , '[]'::jsonb)
where bk.ma_bk = 'BM.QĐ.03.01';

-- BM.QĐ.09.01: Bảng Kiểm Giám Sát Tuân Thủ Môi Trường Bảo Vệ (PE)
update public.gstt_dm_bang_kiem bk set
  hanh_dong_khac_phuc_jsonb = $jsonb$[{"stt":1,"noi_dung":"Đình chỉ và Tịch thu: Tịch thu và đưa ngay ra khỏi phòng bệnh các lẵng hoa tươi, chậu cây cảnh hoặc thực phẩm chưa nấu chín để loại trừ nguồn phát tán bào tử nấm *Aspergillus*.","action_code":"ACT-400","la_stop_the_line":true},{"stt":2,"noi_dung":"Yêu cầu đóng kín cửa phòng bệnh ngay lập tức và kiểm tra lại đồng hồ/luồng khí để đảm bảo áp suất dương đang được duy trì.","action_code":"ACT-200","la_stop_the_line":false},{"stt":3,"noi_dung":"Mời ngay khách thăm hoặc người nhà ra khỏi khu vực PE nếu phát hiện có triệu chứng ho/sốt/cảm cúm hoặc không tuân thủ mang khẩu trang, vệ sinh tay.","action_code":"ACT-200","la_stop_the_line":false},{"stt":4,"noi_dung":"Yêu cầu NVYT quay lại khu vực phòng đệm để thực hiện vệ sinh tay và mang đầy đủ phương tiện phòng hộ trước khi tiếp tục thao tác.","action_code":"ACT-200","la_stop_the_line":false},{"stt":5,"noi_dung":"Yêu cầu nhân viên vệ sinh tiến hành lau ẩm khử khuẩn lại ngay lập tức nếu phát hiện sàn nhà, bề mặt có bụi bẩn hoặc vừa bị quét khô sai quy định.","action_code":"ACT-200","la_stop_the_line":false}]$jsonb$::jsonb,
  nguyen_nhan_cho_phep_jsonb = coalesce(
    (select jsonb_agg(
      jsonb_build_object(
        'lookup_id', l.id::text,
        'lookup_code', l.code,
        'ten_hien_thi', coalesce(e->>'ten_hien_thi', l.name),
        'mo_ta_chi_tiet', coalesce(e->>'mo_ta_chi_tiet', l.description),
        'thu_tu_hien_thi', (e->>'thu_tu_hien_thi')::int
      ) order by (e->>'thu_tu_hien_thi')::int
    ) from jsonb_array_elements($jsonb$[{"lookup_code":"102_SYS","ten_hien_thi":"Thiết kế môi trường/Công thái học bất hợp lý","mo_ta_chi_tiet":"Hệ thống HVAC hỏng không duy trì được áp suất dương, cửa phòng bệnh hỏng bản lề/gioăng cao su nên không thể đóng kín hoàn toàn.","thu_tu_hien_thi":1},{"lookup_code":"103_SYS","ten_hien_thi":"Quá tải công việc / Phân bổ nhân sự chưa phù hợp","mo_ta_chi_tiet":"Tỷ lệ bệnh nhân/nhân viên cao khiến nhân viên vệ sinh không đủ thời gian thực hiện lau khử khuẩn bề mặt phòng PE đạt chuẩn 2 lần/ngày.","thu_tu_hien_thi":2},{"lookup_code":"105_SYS","ten_hien_thi":"Lỗ hổng quy trình / Thiếu y lệnh","mo_ta_chi_tiet":"Khoa lâm sàng không có hướng dẫn rõ ràng về chế độ ăn an toàn cho người bệnh hoặc thiếu quy trình sàng lọc khách thăm trước khi vào phòng.","thu_tu_hien_thi":3},{"lookup_code":"201_HUM","ten_hien_thi":"Yếu tố Kỹ năng / Đào tạo chưa đạt","mo_ta_chi_tiet":"NVYT hoặc NVVS không hiểu rõ nguyên tắc môi trường bảo vệ, sử dụng sai phương pháp vệ sinh (quét khô thay vì lau ẩm làm phát tán bụi).","thu_tu_hien_thi":4},{"lookup_code":"203_HUM","ten_hien_thi":"Hành vi rủi ro \\- Thói quen đi tắt (Workaround)","mo_ta_chi_tiet":"NVYT tiện tay mở toang cửa phòng bệnh để dễ giao tiếp; bỏ qua bước vệ sinh tay trước khi bước vào phòng chăm sóc do nghĩ rằng mình không chạm trực tiếp vào người bệnh.","thu_tu_hien_thi":5},{"lookup_code":"204_HUM","ten_hien_thi":"Yếu tố Tâm sinh lý / Trạng thái cá nhân","mo_ta_chi_tiet":"Điều dưỡng quên kiểm tra và dọn dẹp các lẵng hoa tươi, cây cảnh do người nhà vừa mang vào phòng bệnh do đang bận rộn với y lệnh khác.","thu_tu_hien_thi":6},{"lookup_code":"301_CLI","ten_hien_thi":"Tình huống cấp cứu khẩn cấp","mo_ta_chi_tiet":"Người bệnh diễn biến nặng cần cấp cứu ngừng tuần hoàn, hồi sức tích cực, khiến luồng người ra vào liên tục, không thể duy trì cửa đóng kín và quy trình mặc PTPH đầy đủ.","thu_tu_hien_thi":7},{"lookup_code":"302_CLI","ten_hien_thi":"Yếu tố tâm lý / Hành vi của người bệnh","mo_ta_chi_tiet":"Khách thăm hoặc người nhà không hợp tác, cố tình giấu đồ ăn sống (rau sống, trái cây chưa gọt vỏ) mang vào cho người bệnh, hoặc từ chối đeo khẩu trang khi ở trong phòng.","thu_tu_hien_thi":8}]$jsonb$::jsonb) e
    join public.sys_lookup_value l on l.category_type = 'NGUYEN_NHAN_LOI' and l.code = e->>'lookup_code')
    , '[]'::jsonb)
where bk.ma_bk = 'BM.QĐ.09.01';

-- BM.QĐ.12.01: BẢNG KIỂM GIÁM SÁT VỆ SINH VÀ KHỬ KHUẨN LỒNG ẤP/GIƯỜNG SƯỞI SƠ SINH
update public.gstt_dm_bang_kiem bk set
  hanh_dong_khac_phuc_jsonb = $jsonb$[{"stt":1,"noi_dung":"Đình chỉ ngay lập tức (Stop the line): Dừng ngay thao tác của nhân viên nếu phát hiện họ đang xịt/lau hóa chất khử khuẩn vào bên trong lồng ấp trong khi bệnh nhi sơ sinh vẫn đang nằm bên trong (nguy cơ ngộ độc hóa chất/bỏng hô hấp).","action_code":"ACT-400","la_stop_the_line":true},{"stt":2,"noi_dung":"Yêu cầu nhân viên lấy khăn ẩm thấm nước sạch lau/tráng lại toàn bộ bề mặt bên trong lồng ấp nếu phát hiện còn mùi/vết hóa chất khử khuẩn tồn lưu trước khi đưa trẻ vào.","action_code":"ACT-200","la_stop_the_line":false},{"stt":3,"noi_dung":"Yêu cầu đổ bỏ ngay nước trong bình làm ẩm và thay bằng nước vô khuẩn nếu phát hiện nhân viên đang sử dụng nước máy sinh hoạt.","action_code":"ACT-200","la_stop_the_line":false},{"stt":4,"noi_dung":"Nhắc nhở và yêu cầu Điều dưỡng/Người nhà Vệ sinh tay (cồn) ngay lập tức nếu vừa chạm vào thành lồng ấp mà chuẩn bị sang chăm sóc trẻ khác.","action_code":"ACT-100","la_stop_the_line":false},{"stt":5,"noi_dung":"Cung cấp bút và nhãn dán, yêu cầu nhân viên ghi và dán ngay nhãn \"Đã vệ sinh\" lên các lồng ấp đang trống vừa được xử lý xong để tránh nhầm lẫn với lồng ấp bẩn.","action_code":"ACT-200","la_stop_the_line":false}]$jsonb$::jsonb,
  nguyen_nhan_cho_phep_jsonb = coalesce(
    (select jsonb_agg(
      jsonb_build_object(
        'lookup_id', l.id::text,
        'lookup_code', l.code,
        'ten_hien_thi', coalesce(e->>'ten_hien_thi', l.name),
        'mo_ta_chi_tiet', coalesce(e->>'mo_ta_chi_tiet', l.description),
        'thu_tu_hien_thi', (e->>'thu_tu_hien_thi')::int
      ) order by (e->>'thu_tu_hien_thi')::int
    ) from jsonb_array_elements($jsonb$[{"lookup_code":"101_SYS","ten_hien_thi":"Thiếu vật tư, trang thiết bị tại điểm chăm sóc","mo_ta_chi_tiet":"Khoa hết nước vô khuẩn để châm bình làm ẩm (phải dùng tạm nước thường); thiếu nhãn dán \"Đã vệ sinh\"; hóa chất cấp phát không có khuyến cáo an toàn cho sơ sinh (chứa gốc Phenolic).","thu_tu_hien_thi":1},{"lookup_code":"103_SYS","ten_hien_thi":"Quá tải công việc / Phân bổ nhân sự chưa phù hợp","mo_ta_chi_tiet":"Tỷ lệ bệnh nhi quá đông, không đủ lồng ấp quay vòng (Turnover) khiến Điều dưỡng/Hộ lý phải làm nhanh, bỏ qua thời gian chờ lồng ấp khô hoàn toàn đã vội đưa trẻ mới vào.","thu_tu_hien_thi":2},{"lookup_code":"105_SYS","ten_hien_thi":"Lỗ hổng quy trình / Thiếu y lệnh","mo_ta_chi_tiet":"Không phân định rõ ràng ranh giới giữa việc Điều dưỡng hay Nhân viên vệ sinh (thuê ngoài) chịu trách nhiệm cọ rửa khay nước tạo ẩm bên trong lồng ấp.","thu_tu_hien_thi":3},{"lookup_code":"201_HUM","ten_hien_thi":"Yếu tố Kỹ năng / Đào tạo chưa đạt","mo_ta_chi_tiet":"Nhân viên không biết cách tháo rời khay nước/đệm của lồng ấp để cọ rửa màng sinh học; không biết rằng hóa chất khử khuẩn phải được lau sạch lại bằng nước trước khi dùng cho trẻ sơ sinh.","thu_tu_hien_thi":4},{"lookup_code":"203_HUM","ten_hien_thi":"Hành vi rủi ro \\- Thói quen đi tắt (Workaround)","mo_ta_chi_tiet":"Lười không dán nhãn \"Đã vệ sinh\" sau khi làm xong; cố tình dùng hóa chất khử khuẩn xịt/lau bên trong lồng ấp khi trẻ VẪN ĐANG NẰM TRONG ĐÓ để tiết kiệm thời gian chuyển bệ.","thu_tu_hien_thi":5},{"lookup_code":"204_HUM","ten_hien_thi":"Yếu tố Tâm sinh lý / Trạng thái cá nhân","mo_ta_chi_tiet":"Tâm lý chủ quan, Điều dưỡng chỉ nhớ rửa tay khi chạm trực tiếp vào cơ thể trẻ, nhưng bỏ qua bước vệ sinh tay khi chạm vào thành/nút bấm lồng ấp do không nhận thức được lồng ấp là vùng vi khí hậu của trẻ.","thu_tu_hien_thi":6},{"lookup_code":"301_CLI","ten_hien_thi":"Tình huống cấp cứu khẩn cấp","mo_ta_chi_tiet":"Trẻ sơ sinh đẻ non/ngạt cần hồi sức cấp cứu và phải đưa vào lồng ấp ngay lập tức để ổn định thân nhiệt, nhân viên y tế không có thời gian để chờ lồng ấp khô tự nhiên hoặc chờ dán nhãn niêm phong.","thu_tu_hien_thi":7}]$jsonb$::jsonb) e
    join public.sys_lookup_value l on l.category_type = 'NGUYEN_NHAN_LOI' and l.code = e->>'lookup_code')
    , '[]'::jsonb)
where bk.ma_bk = 'BM.QĐ.12.01';

-- BM.QĐ.16.01: Bảng Kiểm Giám Sát Tuân Thủ An Toàn Sinh Học Phòng Xét Nghiệm
