  hanh_dong_khac_phuc_jsonb = $jsonb$[{"stt":1,"noi_dung":"Đình chỉ và yêu cầu nhân viên y tế lập tức cởi bỏ áo choàng labo/găng tay nếu phát hiện họ định mang/mặc các phương tiện này ra khỏi khu vực xét nghiệm (ra hành lang, nhà ăn, khu vực hành chính).","action_code":"ACT-400","la_stop_the_line":true},{"stt":2,"noi_dung":"Yêu cầu di chuyển ngay các mẫu bệnh phẩm đang xử lý dở dang (có nguy cơ tạo khí dung cao) vào bên trong Tủ An toàn sinh học (BSC) để tiếp tục thao tác.","action_code":"ACT-200","la_stop_the_line":false},{"stt":3,"noi_dung":"Cảnh báo và yêu cầu nhân viên tháo găng, vệ sinh tay ngay lập tức nếu phát hiện họ dùng găng tay đang xử lý bệnh phẩm để chạm vào các bề mặt sạch (bàn phím, điện thoại, hồ sơ).","action_code":"ACT-200","la_stop_the_line":false},{"stt":4,"noi_dung":"Phong tỏa tạm thời khu vực và hướng dẫn nhân viên sử dụng Bộ xử lý tràn đổ (Spill Kit) ngay lập tức nếu phát hiện có ống bệnh phẩm bị vỡ hoặc máu/dịch rò rỉ trên bàn xét nghiệm/máy ly tâm.","action_code":"ACT-200","la_stop_the_line":false},{"stt":5,"noi_dung":"Nhắc nhở và yêu cầu bổ sung ngay kính bảo hộ/tấm che mặt trước khi Kỹ thuật viên tiếp tục các thao tác mở nắp ống nghiệm có áp lực hoặc pha chế hóa chất/bệnh phẩm văng bắn.","action_code":"ACT-100","la_stop_the_line":false}]$jsonb$::jsonb,
  nguyen_nhan_cho_phep_jsonb = coalesce(
    (select jsonb_agg(
      jsonb_build_object(
        'lookup_id', l.id::text,
        'lookup_code', l.code,
        'ten_hien_thi', coalesce(e->>'ten_hien_thi', l.name),
        'mo_ta_chi_tiet', coalesce(e->>'mo_ta_chi_tiet', l.description),
