  hanh_dong_khac_phuc_jsonb = $jsonb$[{"stt":1,"noi_dung":"Đình chỉ hệ thống (Stop the Line): Yêu cầu dừng toàn bộ hoạt động pha chế ngay lập tức nếu phát hiện phòng sạch mất áp suất hoặc Tủ BSC không hoạt động. Báo cáo khẩn cấp bộ phận kỹ thuật để xử lý.","action_code":"ACT-400","la_stop_the_line":true},{"stt":2,"noi_dung":"Yêu cầu Dược sĩ/NVYT ra ngoài phòng đệm để tháo bỏ trang sức, rửa tay lại và mặc bộ PTPH vô khuẩn mới nếu phát hiện lỗi vi phạm (để lộ tóc, chạm tay vào bề mặt không vô khuẩn, rách găng).","action_code":"ACT-200","la_stop_the_line":false},{"stt":3,"noi_dung":"Yêu cầu tiêu hủy ngay lập tức túi dịch hoặc sản phẩm đang pha chế nếu quan sát thấy bơm kim tiêm hoặc đầu nối vô khuẩn bị chạm vào môi trường không vô khuẩn bên ngoài hoặc chạm vào thành tủ.","action_code":"ACT-200","la_stop_the_line":false},{"stt":4,"noi_dung":"Yêu cầu NVYT lấy gạc tẩm Cồn 70° lau sát khuẩn lại toàn bộ bề mặt vật tư, thiết bị và bắt buộc chờ khô trước khi tiếp tục đưa vào không gian thao tác của Tủ BSC.","action_code":"ACT-200","la_stop_the_line":false},{"stt":5,"noi_dung":"Nhắc nhở và hướng dẫn lại tại chỗ (Coaching) về vị trí đặt tay, sắp xếp vật tư trong tủ BSC (cách thành tủ 15cm, không chắn luồng khí sạch HEPA).","action_code":"ACT-100","la_stop_the_line":false}]$jsonb$::jsonb,
  nguyen_nhan_cho_phep_jsonb = coalesce(
    (select jsonb_agg(
      jsonb_build_object(
        'lookup_id', l.id::text,
        'lookup_code', l.code,
        'ten_hien_thi', coalesce(e->>'ten_hien_thi', l.name),
        'mo_ta_chi_tiet', coalesce(e->>'mo_ta_chi_tiet', l.description),
        'thu_tu_hien_thi', (e->>'thu_tu_hien_thi')::int
      ) order by (e->>'thu_tu_hien_thi')::int
    ) from jsonb_array_elements($jsonb$[{"lookup_code":"101_SYS","ten_hien_thi":"Thiếu vật tư, trang thiết bị tại điểm chăm sóc","mo_ta_chi_tiet":"Thiếu găng tay vô khuẩn, thiếu áo choàng vô khuẩn dùng 1 lần, hết gạc tẩm cồn 70° để sát khuẩn vật tư.","thu_tu_hien_thi":1},{"lookup_code":"104_SYS","ten_hien_thi":"Lỗi thiết bị kỹ thuật / Hỏng hóc máy móc","mo_ta_chi_tiet":"Hệ thống HVAC hỏng làm mất áp suất chuẩn của phòng sạch (không duy trì được áp suất dương/âm), Tủ an toàn sinh học (BSC) bị lỗi màng lọc HEPA hoặc hỏng quạt hút khí.","thu_tu_hien_thi":2},{"lookup_code":"201_HUM","ten_hien_thi":"Yếu tố Kỹ năng / Đào tạo chưa đạt","mo_ta_chi_tiet":"Thực hiện sai quy trình mặc PTPH (gowning) để lộ da/tóc; thao tác tay bên trong tủ BSC sai kỹ thuật làm che khuất luồng khí HEPA gây nhiễu loạn dòng khí vô trùng.","thu_tu_hien_thi":3},{"lookup_code":"203_HUM","ten_hien_thi":"Hành vi rủi ro \\- Thói quen đi tắt (Workaround)","mo_ta_chi_tiet":"Đưa trực tiếp lọ thuốc, túi dịch vào tủ BSC mà không lau sát khuẩn bề mặt ngoài bằng Cồn 70°; đâm kim rút thuốc khi cồn sát khuẩn trên cổng cao su chưa khô hoàn toàn.","thu_tu_hien_thi":4},{"lookup_code":"204_HUM","ten_hien_thi":"Yếu tố Tâm sinh lý / Trạng thái cá nhân","mo_ta_chi_tiet":"Quên bật tủ BSC chạy không khí 15-30 phút trước khi làm việc hoặc quên ghi chép, dán nhãn truy xuất lên túi dịch sau khi pha xong do áp lực công việc phải chuẩn bị thuốc gấp.","thu_tu_hien_thi":5},{"lookup_code":"205_HUM","ten_hien_thi":"Hành vi liều lĩnh (Reckless behavior)","mo_ta_chi_tiet":"Cố tình đeo trang sức, đồng hồ, trang điểm vào khu vực pha chế hoặc cố tình sử dụng lại bơm kim tiêm đã qua sử dụng để rút thuốc từ các lọ đa liều bất chấp quy định an toàn.","thu_tu_hien_thi":6}]$jsonb$::jsonb) e
    join public.sys_lookup_value l on l.category_type = 'NGUYEN_NHAN_LOI' and l.code = e->>'lookup_code')
    , '[]'::jsonb)
where bk.ma_bk = 'BM.QĐ.17.01';

